elements.content:
flowchart LR
  code[Your Script] --> engine[JS Engine]
  subgraph browser[Browser Runtime]
    engine --> sandbox[Safe Sandbox]
    engine --> timers[Timers API]
    engine --> network[Network API]
    engine --> dom[Page APIs]
    html[HTML + CSS] --- dom
  end

  classDef hot fill:#ffd166,stroke:#ffb703,color:#111,stroke-width:3px;
  classDef cool fill:#118ab2,stroke:#06d6a0,color:#fff,stroke-width:2px;
  classDef dark fill:#1f2937,stroke:#64748b,color:#fff,stroke-width:2px;
  class engine hot;
  class timers,network,dom cool;
  class code,html,sandbox dark;

flowchart BT
  bottom[global script] --> fnA[loadUser]
  fnA --> fnB[formatName]
  fnB --> fnC[console.log]

  classDef active fill:#ffd166,stroke:#ffb703,color:#111,stroke-width:3px;
  classDef stack fill:#253044,stroke:#94a3b8,color:#fff,stroke-width:2px;
  class bottom,fnA,fnB stack;
  class fnC active;

flowchart LR
  js[JS Engine] --> fetchCall[fetch request]
  js --> timerCall[setTimeout]

  fetchCall --> net[Networking API]
  timerCall --> timer[Timers API]
  net --> server[Remote Server]
  timer --> alarm[Timer Complete]

  classDef engine fill:#ffd166,stroke:#ffb703,color:#111,stroke-width:3px;
  classDef api fill:#118ab2,stroke:#06d6a0,color:#fff,stroke-width:2px;
  classDef work fill:#1f2937,stroke:#64748b,color:#fff,stroke-width:2px;
  class js engine;
  class net,timer api;
  class fetchCall,timerCall,server,alarm work;

flowchart TB
  done[Background Work Finishes] --> decision{What kind of callback?}
  decision --> promise[Promise.then callback]
  decision --> event[Click or timer callback]

  promise --> micro[Microtask Queue]
  event --> task[Task Queue]

  classDef hot fill:#ffd166,stroke:#ffb703,color:#111,stroke-width:3px;
  classDef micro fill:#7c3aed,stroke:#c084fc,color:#fff,stroke-width:3px;
  classDef task fill:#0ea5e9,stroke:#67e8f9,color:#fff,stroke-width:3px;
  classDef neutral fill:#1f2937,stroke:#64748b,color:#fff,stroke-width:2px;
  class done,decision neutral;
  class promise,micro micro;
  class event,task task;

flowchart LR
  taskQ[Task Queue] --> loop[Event Loop]
  loop --> stack[Call Stack]
  stack --> complete[Task Complete]
  complete --> microQ[Microtask Queue]
  microQ --> drain[Drain Microtasks]
  drain --> loop

  classDef loopClass fill:#ffd166,stroke:#ffb703,color:#111,stroke-width:4px;
  classDef queue fill:#118ab2,stroke:#06d6a0,color:#fff,stroke-width:2px;
  classDef stackClass fill:#ef476f,stroke:#ff8fab,color:#fff,stroke-width:2px;
  classDef neutral fill:#1f2937,stroke:#64748b,color:#fff,stroke-width:2px;
  class loop loopClass;
  class taskQ,microQ,drain queue;
  class stack stackClass;
  class complete neutral;

const sayHello = () => console.log('Hello');

console.log('start');
sayHello();
setTimeout(() => console.log('later'), 0);
console.log('end');

// start
// Hello
// end
// later

flowchart LR
  user[User Click] --> button[Button]
  button --> eventTask[Click Task]
  eventTask --> taskQ[Task Queue]
  taskQ --> loop[Event Loop]
  loop --> handler[Event Handler]
  handler --> stack[Call Stack]

  classDef userClass fill:#ffd166,stroke:#ffb703,color:#111,stroke-width:3px;
  classDef queue fill:#0ea5e9,stroke:#67e8f9,color:#fff,stroke-width:3px;
  classDef loopClass fill:#7c3aed,stroke:#c084fc,color:#fff,stroke-width:3px;
  classDef stackClass fill:#ef476f,stroke:#ff8fab,color:#fff,stroke-width:3px;
  classDef neutral fill:#1f2937,stroke:#64748b,color:#fff,stroke-width:2px;
  class user userClass;
  class eventTask,taskQ queue;
  class loop loopClass;
  class handler,stack stackClass;
  class button neutral;

flowchart LR
  page[Page Code] --> fetch[fetch]
  fetch --> net[Networking API]
  net --> response[Response Arrives]
  response --> promise[Promise Resolved]
  promise --> microQ[Microtask Queue]
  microQ --> callback[then callback]
  callback --> stack[Call Stack]

  classDef pageClass fill:#ffd166,stroke:#ffb703,color:#111,stroke-width:3px;
  classDef api fill:#118ab2,stroke:#06d6a0,color:#fff,stroke-width:2px;
  classDef micro fill:#7c3aed,stroke:#c084fc,color:#fff,stroke-width:3px;
  classDef stackClass fill:#ef476f,stroke:#ff8fab,color:#fff,stroke-width:3px;
  classDef neutral fill:#1f2937,stroke:#64748b,color:#fff,stroke-width:2px;
  class page pageClass;
  class fetch,net api;
  class promise,microQ,callback micro;
  class stack stackClass;
  class response neutral;
